async function runTasks(tasks, concurrency) {
  const results = new Array(tasks.length);
  const running = new Set();

  for (let i = 0; i < tasks.length; i++) {
    const task = tasks[i];

    // Wrap the execution to handle results, errors, and Set cleanup
    const executionPromise = (async () => {
      try {
        results[i] = await task();
      } catch (error) {
        // Ensure the error is returned as an object
        results[i] = error instanceof Error ? error : new Error(String(error));
      }
    })();

    // Add to our Set of running tasks
    running.add(executionPromise);

    // Remove from the Set once finished
    executionPromise.finally(() => {
      running.delete(executionPromise);
    });

    // Enforce concurrency limit
    if (running.size >= concurrency) {
      await Promise.race(running);
    }
  }

  // Wait for all remaining tasks to finish
  await Promise.all(running);

  return results;
}

