function deepMerge(target, source, visited = new WeakMap()) {
  const isObject = (obj) => obj !== null && typeof obj === 'object';

  // If source is not an object, return it directly
  if (!isObject(source)) {
    return source;
  }

  // Handle circular references
  if (visited.has(source)) {
    return visited.get(source);
  }

  // Create a new object or array to ensure no mutation of the input target
  const result = Array.isArray(target) ? [...target] : { ...target };

  // Register the current source object in the visited map
  visited.set(source, result);

  for (const key of Object.keys(source)) {
    // Prevent Prototype Pollution
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      continue;
    }

    const sourceValue = source[key];
    const targetValue = result[key];

    if (isObject(sourceValue)) {
      // Recursively merge if the source property is an object
      result[key] = deepMerge(
        isObject(targetValue) ? targetValue : (Array.isArray(sourceValue) ? [] : {}),
        sourceValue,
        visited
      );
    } else {
      // Otherwise, assign the value directly
      result[key] = sourceValue;
    }
  }

  return result;
}
