 * Prevents Prototype Pollution and handles Circular References.
 * 
 * @param {Object} target - The base object.
 * @param {Object} source - The object to merge from.
 * @param {WeakMap} visited - Internal map for circular reference tracking.
 * @returns {Object} - A new merged object.
 */
function deepMerge(target, source, visited = new WeakMap()) {
  // 1. Handle non-object types or nulls
  if (source === null || typeof source !== 'object') {
    return source;
  }

  // 2. Prevent Circular References
  if (visited.has(source)) {
    return visited.get(source);
  }

  // 3. Prevent Prototype Pollution: List of forbidden keys
  const FORBIDDEN_KEYS = ["__proto__", "constructor", "prototype"];

  // 4. Create a new object/array to ensure No Mutation
  // We initialize the result as a clone of the target
  const result = Array.isArray(target) 
    ? [...target] 
    : (target !== null && typeof target === 'object' ? { ...target } : {});

  // Register the source in visited map to track circularity
  visited.set(source, result);

  // 5. Iterate through source keys
  const keys = Object.keys(source);
  for (const key of keys) {
    // Security check: Block Prototype Pollution
    if (FORBIDDEN_KEYS.includes(key)) {
      continue;
    }

    const sourceValue = source[key];
    const targetValue = result[key];

    if (sourceValue !== null && typeof sourceValue === 'object') {
      // If the value is an object, recurse
      result[key] = deepMerge(targetValue, sourceValue, visited);
    } else {
      // Otherwise, assign the primitive value/reference
      result[key] = sourceValue;
    }
  }

  return result;
}

