   * @param {any} targetValue - The value from the target object.
   * @param {any} sourceValue - The value from the source object.
   * @returns {any} The merged value.
   */
  function mergeRecursively(targetValue, sourceValue) {
    // Helper function to determine if a value is a plain object that can be merged.
    const isObject = (obj) => obj && typeof obj === 'object' && !Array.isArray(obj);

    const isSourceAnObject = isObject(sourceValue);
    const isTargetAnObject = isObject(targetValue);

    // If the source is not a plain object, it cannot be deeply merged.
    // In this case, the source value replaces the target value.
    if (!isSourceAnObject) {
      return sourceValue;
    }

    // Handle circular references. If we've already processed this source object,
    // return the previously created merged object to break the loop.
    if (visited.has(sourceValue)) {
      return visited.get(sourceValue);
