    // If the source is an object but the target is not, start with an empty object as the base.
    const currentTarget = isTargetAnObject ? targetValue : {};

    // Create a new object for the result, starting with a shallow copy of the target.
    // This is the core of the non-mutating behavior.
    const merged = { ...currentTarget };

    // IMPORTANT: Store the newly created merged object in the map *before* recursing.
    // This handles cases where an object contains a reference to itself.
    visited.set(sourceValue, merged);

    // Iterate over the keys of the source object to perform the merge.
    for (const key in sourceValue) {
