        // Recursively call the merge function for each property. The result will be
        // a new merged value/object, which we assign to our new 'merged' object.
        merged[key] = mergeRecursively(currentTarget[key], sourceValue[key]);
      }
    }

    return merged;
  }

  // Start the merge process and return the newly created object.
  return mergeRecursively(target, source);
