/**
 * Runs a collection of asynchronous tasks with a specified concurrency limit.
 *
 * @param {Array<Function<Promise>>} tasks - An array of async functions (thunks) to execute.
 * @param {number} concurrency - The maximum number of tasks to run simultaneously.
 * @returns {Promise<Array<any>>} A promise that resolves with an array of results
 * in the original order. If a task rejects, the Error object is placed in the
 * results array.
 */
async function runTasks(tasks, concurrency) {
  // Handle the edge case of an empty task list.
  if (tasks.length === 0) {
    return [];
  }

  return new Promise(resolve => {
    const results = new Array(tasks.length);
    // Use a Set to track the promises of the tasks currently running.
    const running = new Set();
    // Index of the next task to be started from the tasks array.
    let taskIndex = 0;
    // Count of tasks that have been completed.
    let completedTasks = 0;

    /**
     * Schedules the next available tasks until the concurrency limit is reached.
     */
    function scheduleNext() {
      // Loop as long as there's capacity in the pool and tasks are available.
      while (running.size < concurrency && taskIndex < tasks.length) {
        const currentIndex = taskIndex;
        const task = tasks[taskIndex];
        taskIndex++;

        // Create a wrapper promise to execute the task and handle its outcome.
        // This IIFE (Immediately Invoked Function Expression) ensures that
        // the task starts executing right away.
        const promise = (async () => {
          try {
            // Execute the task and wait for its result.
            return await task();
          } catch (error) {
            // If the task's promise rejects, return the error object.
            return error;
          }
        })();

        // Add the new promise to the set of running tasks.
        running.add(promise);

        // Handle the completion of the task.
        promise.then(result => {
          // Store the result in the correct position to maintain order.
          results[currentIndex] = result;

          // The task is no longer running, so remove its promise from the set.
          running.delete(promise);

          completedTasks++;

          // If all tasks have been completed, resolve the main promise.
          if (completedTasks === tasks.length) {
            resolve(results);
          } else {
            // Otherwise, there's now capacity, so try to schedule another task.
            scheduleNext();
          }
        });
      }
    }

    // Kick off the initial scheduling process.
    scheduleNext();
  });
