async function runTasks(tasks, concurrency) {
  // If no tasks are provided, return an empty array immediately.
  if (!tasks || tasks.length === 0) {
    return [];
  }

  const results = new Array(tasks.length);
  const running = new Set();
  const promises = []; // Used to await all tasks at the end.

  for (let i = 0; i < tasks.length; i++) {
    // If the number of running tasks has reached the concurrency limit,
    // wait for any of them to finish. Promise.race resolves as soon as
    // one of the promises in the iterable settles.
    if (running.size >= concurrency) {
      await Promise.race(running);
    }

    const task = tasks[i];

    // Create a promise chain for the current task.
    // 'let i' in the for-loop ensures 'i' is correctly scoped for each iteration.
    const promise = task()
      .then(result => {
        results[i] = result;
      })
      .catch(error => {
        results[i] = error;
      })
      .finally(() => {
        // Once the promise has settled (resolved or rejected),
        // remove it from the set of running promises.
        running.delete(promise);
      });

    // Add the new promise to the set of running promises.
    running.add(promise);
    // Also add it to the final list of all promises to await their completion.
    promises.push(promise);
  }

