 * @param {string} str The string of commands to parse.
 * @returns {number} The final computed state.
 * @throws {TypeError} If the input is not a string or contains invalid characters.
 */
function parseCommands(str) {
  // Guard against non-string inputs for robustness.
  if (typeof str !== 'string') {
    throw new TypeError('Input must be a string.');
