/**
 * An implementation of a Least Recently Used (LRU) Cache.
 *
 * This class adheres to the following constraints:
 * - It MUST use an ES6 `Map` to achieve O(1) time complexity for its operations.
 * - It MUST rely on the Map's native insertion order to track recency.
 * - When evicting an item, it MUST use `this.cache.keys().next().value` to get the oldest key.
 */
class LRUCache {
  /**
   * @param {number} capacity The maximum number of items the cache can hold.
   */
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map();
  }

  /**
   * Retrieves the value for a given key.
   * If the key exists, it is marked as the most recently used item.
   * @param {any} key The key to retrieve.
   * @returns {number} The value associated with the key, or -1 if the key is not found.
   */
  get(key) {
    // If the key does not exist in the cache, return -1.
    if (!this.cache.has(key)) {
      return -1;
    }

    // The key exists. Retrieve its value.
    const value = this.cache.get(key);

    // To mark this item as the most recently used, we must move it to the
    // end of the Map's insertion order. This is achieved by deleting the
    // key and setting it again.
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  /**
   * Sets a key-value pair in the cache.
   * If the key already exists, its value is updated, and it is marked as the
   * most recently used item.
   * If the cache is at capacity, the least recently used item is evicted.
   * @param {any} key The key to set.
   * @param {any} value The value to associate with the key.
   * @returns {void}
   */
  set(key, value) {
    // If the key already exists, we must delete it first to ensure its
    // position is updated when we set it again, making it the most recent.
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }

    // Set the key and value. This places the item at the end of the
    // insertion order, making it the most recently used.
    this.cache.set(key, value);

    // After adding the new item, check if the cache has exceeded its capacity.
    if (this.cache.size > this.capacity) {
      // Evict the least recently used item. In a Map, this is the first item
      // in its insertion order. We use the mandated method to get its key.
      const oldestKey = this.cache.keys().next().value;
      this.cache.delete(oldestKey);
    }
  }
}

