 */
class LRUCache {
  /**
   * @param {number} capacity The maximum number of items the cache can hold.
   */
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map();
  }

  /**
   * Retrieves the value for a given key. Returns -1 if the key is not in the cache.
   * Accessing a key marks it as the most recently used item.
   * @param {*} key The key to retrieve.
   * @returns {*} The value associated with the key, or -1 if not found.
   */
  get(key) {
    // If the key does not exist in the cache, return -1.
    if (!this.cache.has(key)) {
      return -1;
    }

    // To mark this item as most recently used, we move it to the end of the
    // Map's insertion order. The most direct way to do this is to delete
    // the existing entry and then set it again.
    const value = this.cache.get(key);
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  /**
   * Sets a key-value pair in the cache. If the key already exists, its value
   * is updated. Setting a key also marks it as the most recently used item.
   * If adding the new item exceeds the cache's capacity, the least recently
   * used item is evicted.
