    // If the key already exists, we must delete it first. This is crucial
    // for ensuring its position is updated to be the most recent when we set it again.
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }

    // Set the new key-value pair. It will be added to the end of the insertion order,
    // making it the most recently used item.
    this.cache.set(key, value);

    // Check if the cache size now exceeds its capacity.
    if (this.cache.size > this.capacity) {
      // If capacity is exceeded, evict the least recently used item.
      // A Map's iterator yields items in insertion order, so the first key is the oldest.
