async function runTasks(tasks, concurrency) {
  // Array to store results in the correct order.
  const results = new Array(tasks.length);
  // Set to track promises of currently running tasks.
  const runningPromises = new Set();
  // Index to keep track of the next task to be started.
  let taskIndex = 0;

  // The entire function returns a promise that resolves when all tasks are done.
  return new Promise((resolve) => {
    // Controller function to manage starting new tasks.
    const runNextTask = () => {
      // Base case: If all tasks have been started and all have completed,
      // resolve the main promise with the results.
      if (taskIndex >= tasks.length && runningPromises.size === 0) {
        resolve(results);
        return;
      }

      // While there are concurrency slots available and tasks remaining...
      while (runningPromises.size < concurrency && taskIndex < tasks.length) {
        const currentIndex = taskIndex;
        const task = tasks[taskIndex];
        taskIndex++;

        // Create and execute the promise for the current task.
        const promise = (async () => {
          try {
            // Await the task and store the result at its original index.
            results[currentIndex] = await task();
          } catch (error) {
            // If the task fails, store the Error object at its original index.
            results[currentIndex] = error;
          }
        })();

        // Add the new promise to the set of running promises.
        runningPromises.add(promise);

        // When the promise settles (either resolves or rejects)...
        promise.finally(() => {
          // Remove it from the running set.
          runningPromises.delete(promise);
          // Call this function again to check if a new task can be started.
          runNextTask();
        });
      }
    };

    // Kick off the initial batch of tasks.
    runNextTask();
  });
}

