class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key) {
    if (!this.cache.has(key)) {
      return -1;
    }

    const value = this.cache.get(key);
    // By deleting and re-setting the key, we move it to the end of the
    // Map's insertion order, marking it as the most recently used.
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key, value) {
    // If the key already exists, we must delete it first to ensure
    // it's moved to the end when we set it again.
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }

    this.cache.set(key, value);

    // After insertion, check if the cache has exceeded its capacity.
    if (this.cache.size > this.capacity) {
      // The Map object maintains insertion order. The first item in the
      // keys iterator is the oldest (least recently used) item.
      const oldestKey = this.cache.keys().next().value;
      this.cache.delete(oldestKey);
    }
  }
}

