async function runTasks(tasks, concurrency) {
  if (concurrency <= 0) {
    throw new Error("Concurrency must be a positive integer.");
  }

  const results = new Array(tasks.length); // Array to store results, maintaining original order
  const runningPromises = new Set(); // Set to track currently running promises
  const allTaskCompletionPromises = []; // Stores the promises representing the actual task executions

  // Helper function to execute a single task, handle its result or error,
  // and store it in the `results` array at the correct index.
  const executeTask = async (taskFn, index) => {
    try {
      const result = await taskFn();
      results[index] = result;
    } catch (error) {
      // On rejection, store the Error object directly in the results array
      results[index] = error;
    }
  };

  for (let i = 0; i < tasks.length; i++) {
    // 1. Create a promise that represents the execution of the current task.
    // This promise will resolve/reject and populate `results[i]`.
    const taskExecutionPromise = executeTask(tasks[i], i);

    // Add this promise to a list of all task promises. We will await all of them
    // at the end to ensure all results are populated before returning.
    allTaskCompletionPromises.push(taskExecutionPromise);

    // 2. Create a "managed" promise that wraps the `taskExecutionPromise`.
    // This `managedPromise` is the one we add to the `runningPromises` Set.
    // When it settles (either resolves or rejects), it will remove itself
    // from the `runningPromises` Set, effectively freeing up a slot.
    const managedPromise = taskExecutionPromise.finally(() => {
      runningPromises.delete(managedPromise);
    });

    // 3. Add the managed promise to the Set of currently running promises.
    runningPromises.add(managedPromise);

    // 4. If the concurrency limit is reached, wait for any currently running
    // managed promise to complete. This pause allows a slot to free up
    // before the loop proceeds to initiate more tasks.
    if (runningPromises.size >= concurrency) {
      await Promise.race(runningPromises);
    }
  }

  // After all tasks have been initiated, wait for any remaining tasks
  // (whose promises are still in `allTaskCompletionPromises`) to complete.
  // This ensures that the `results` array is fully populated before it's returned.
  await Promise.allSettled(allTaskCompletionPromises);

  return results;
}
