class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map(); // Use ES6 Map to store key-value pairs and maintain insertion order
  }

  /**
   * Retrieves a value from the cache.
   * If the key exists, it marks it as most recently used by re-inserting it at the end.
   * @param {number} key
   * @return {number} The value associated with the key, or -1 if not found.
   * Time Complexity: O(1) on average.
   */
  get(key) {
    if (!this.cache.has(key)) {
      return -1;
    }

    // Get the value associated with the key
    const value = this.cache.get(key);

    // Remove the key-value pair from its current position
    // This effectively "moves" it to the front of the eviction queue (end of the Map)
    this.cache.delete(key);

    // Re-insert the key-value pair at the end of the Map
    // This updates its position to be the most recently used
    this.cache.set(key, value);

    return value;
  }

  /**
   * Sets or updates a value in the cache.
   * If the key already exists, its value is updated and it becomes most recently used.
   * If the key is new and capacity is exceeded, the least recently used item is removed.
   * @param {number} key
   * @param {number} value
   * @return {void}
   * Time Complexity: O(1) on average.
   */
  set(key, value) {
    // If the key already exists, delete it first to update its position
    // It will be re-inserted at the end, making it most recently used.
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }
    // If the key is new AND the cache is at its capacity,
    // we need to evict the least recently used item.
    else if (this.cache.size >= this.capacity) {
      // Get the oldest key, which is the first entry in the Map due to insertion order.
      const oldestKey = this.cache.keys().next().value;
      this.cache.delete(oldestKey); // Remove the oldest item
    }

    // Add or update the new key-value pair.
    // This places it at the end of the Map, making it the most recently used.
    this.cache.set(key, value);
  }
}
