  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map(); // Use ES6 Map
  }

  get(key) {
    if (!this.cache.has(key)) {
      return -1;
    }

    const value = this.cache.get(key);
    // To mark as most recently used, delete and re-insert
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key, value) {
    // If key already exists, delete it first to update its position to MRU
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } 
    // If adding a new key and cache is full
    else if (this.cache.size >= this.capacity) {
      // Evict the least recently used item
      // The first key in the Map's iteration order is the oldest
      const oldestKey = this.cache.keys().next().value;
      this.cache.delete(oldestKey);
    }

    // Add or re-add the key with its new/updated value
    // This places it at the end, making it the most recently used
    this.cache.set(key, value);
  }
}

