class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map(); // Use ES6 Map as required
  }

  get(key) {
    if (!this.cache.has(key)) {
      return -1;
    }

    const value = this.cache.get(key);
    // To mark this key as most recently used, we delete it and re-insert it.
    // Map's iteration order is insertion order, so re-inserting puts it at the end.
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key, value) {
    // Handle capacity 0: no items can be stored.
    if (this.capacity === 0) {
      return;
    }

    // If the key already exists, delete it first.
    // This is necessary so that when we re-add it, it moves to the end
    // of the Map's iteration order, becoming the most recently used.
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }

    // Check if the cache is at or over capacity.
    // If it is, we need to evict the least recently used item before adding the new one.
    if (this.cache.size >= this.capacity) {
      // Get the key of the least recently used item.
      // This is the first item in the Map's insertion order.
      const oldestKey = this.cache.keys().next().value; // Strictly adheres to the instruction.
      this.cache.delete(oldestKey); // Evict the oldest item.
    }

    // Add the new key-value pair (or re-add the updated one).
    // This places it at the end of the Map's iteration order, making it MRU.
    this.cache.set(key, value);
  }
}

