async function runTasks(tasks, concurrency) {
  const results = new Array(tasks.length); // Pre-allocate results array to maintain order
  const runningPromises = new Set(); // Track currently running promises
  let taskIndex = 0; // Pointer to the next task to start

  return new Promise((resolve, reject) => {
    function scheduleNextTask() {
      // If all tasks have been scheduled and all running promises are done, we're finished.
      if (taskIndex === tasks.length && runningPromises.size === 0) {
        resolve(results);
        return;
      }

      // While there are tasks to schedule and we have capacity
      while (taskIndex < tasks.length && runningPromises.size < concurrency) {
        const currentTaskIndex = taskIndex;
        const taskFn = tasks[currentTaskIndex];
        taskIndex++;

        // Wrap the task execution with error handling and index tracking
        const promise = (async () => {
          try {
            return await taskFn();
          } catch (e) {
            return e; // Return the error object on rejection
          }
        })();

        // Add to running promises set
        const runningPromiseWithCleanup = promise.finally(() => {
          runningPromises.delete(runningPromiseWithCleanup); // Remove self from set when done
          scheduleNextTask(); // Try to schedule more tasks once a slot is free
        });

        runningPromises.add(runningPromiseWithCleanup);

        // Store the result directly into the pre-allocated array when it settles
        runningPromiseWithCleanup.then(value => {
          results[currentTaskIndex] = value;
        });
      }

      // If we've hit concurrency limit or no more tasks to schedule,
      // wait for one of the running tasks to complete to free up a slot.
      if (runningPromises.size >= concurrency || (taskIndex === tasks.length && runningPromises.size > 0)) {
        // We don't await Promise.race here directly in the outer function flow,
        // as `scheduleNextTask` is called from `finally` to re-trigger scheduling.
        // This effectively creates a self-managing loop.
        // The outer Promise will only resolve once `scheduleNextTask` finds
        // both `taskIndex === tasks.length` and `runningPromises.size === 0`.
      }
    }

    // Start the scheduling process
    scheduleNextTask();
  });
}

