  const visited = new WeakMap(); // Tracks objects that have been cloned/merged to handle circular references

  /**
   * Recursive helper function for deep merging.
   * @param {*} targetVal The value from the target object at the current path.
   * @param {*} sourceVal The value from the source object at the current path.
   * @param {WeakMap} visited Map to track circular references.
   * @returns {*} A new deeply merged value.
   */
  function _mergeRecursive(targetVal, sourceVal, visited) {
    // 1. Handle primitives, null, functions, Date, RegExp
    if (sourceVal === null || typeof sourceVal !== 'object') {
      return sourceVal; // Primitive, null, or function in source overwrites target.
    }

    if (sourceVal instanceof Date) {
      return new Date(sourceVal.getTime());
    }
    if (sourceVal instanceof RegExp) {
      return new RegExp(sourceVal.source, sourceVal.flags);
    }

    // 2. Handle circular references for sourceVal
    if (visited.has(sourceVal)) {
      return visited.get(sourceVal);
    }

    // 3. Initialize result based on sourceVal's type
    // If targetVal is compatible (same type, non-primitive, non-null, non-Date/RegExp),
    // we use a shallow copy of targetVal as the base for merging.
    // Otherwise, we start with an empty object/array based on sourceVal's type.
    let result;
    const isSourceArray = Array.isArray(sourceVal);
    const isTargetArray = Array.isArray(targetVal);

    if (
      targetVal !== null && typeof targetVal === 'object' &&
      !(targetVal instanceof Date) && !(targetVal instanceof RegExp) &&
      isSourceArray === isTargetArray // Both are arrays OR both are objects
    ) {
      result = isTargetArray ? [...targetVal] : { ...targetVal }; // Shallow copy existing target
    } else {
      result = isSourceArray ? [] : {}; // Start fresh based on source type
    }

    // Mark sourceVal as visited with the newly created result object/array
    // This allows detection of future circular references to sourceVal within its own subtree
    visited.set(sourceVal, result);

    // 4. Merge properties from sourceVal into result
    for (const key of Object.keys(sourceVal)) {
      // 5. Prototype Pollution Prevention
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        continue; // Skip dangerous keys
      }

      const currentSourceProp = sourceVal[key];
      const currentTargetProp = result[key]; // This could be from initial shallow copy of targetVal or undefined

      // If both currentSourceProp and currentTargetProp are mergeable objects/arrays of the same type
      if (
        currentSourceProp !== null && typeof currentSourceProp === 'object' &&
        !(currentSourceProp instanceof Date) && !(currentSourceProp instanceof RegExp) &&
        currentTargetProp !== null && typeof currentTargetProp === 'object' &&
        !(currentTargetProp instanceof Date) && !(currentTargetProp instanceof RegExp) &&
        Array.isArray(currentSourceProp) === Array.isArray(currentTargetProp)
      ) {
