        result[key] = _mergeRecursive(currentTargetProp, currentSourceProp, visited);
      } else {
        // Otherwise, overwrite result[key] with a deep clone of currentSourceProp
        // This ensures immutability of source's sub-objects and handles primitives/type mismatches.
        result[key] = _mergeRecursive(null, currentSourceProp, visited); // Pass null for targetPart to force deep clone of sourceProp
      }
    }

    return result;
  }

