class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map(); // Use Map as required for O(1) and insertion order
  }

  get(key) {
    if (!this.cache.has(key)) {
      return -1; // Key not found
    }

    const value = this.cache.get(key); // Get the value
    this.cache.delete(key);           // Delete the key to update its position
    this.cache.set(key, value);       // Re-insert the key-value pair, making it most recently used
    return value;
  }

  set(key, value) {
    if (this.cache.has(key)) {
      this.cache.delete(key); // If key already exists, delete it to update its recency
    }

    this.cache.set(key, value); // Add or re-add the new key-value pair, making it most recently used

    // If capacity is exceeded, evict the least recently used item
    if (this.cache.size > this.capacity) {
      // The oldest item is the first one in the Map's iteration order
      const oldestKey = this.cache.keys().next().value; // Exactly as specified
      this.cache.delete(oldestKey);
    }
  }
}

