    this.capacity = capacity;
    this.cache = new Map(); // Use Map as required
  }

  get(key) {
    if (!this.cache.has(key)) {
      return -1; // Key not found
    }

    // Get the value associated with the key
    const value = this.cache.get(key);

    // To mark this key as Most Recently Used (MRU),
    // delete it and re-insert it. Map maintains insertion order.
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
  }

  set(key, value) {
    // If the key already exists, delete it first to update its recency
    if (this.cache.has(key)) {
      this.cache.delete(key);
    }

    // If the cache is at full capacity AND we are adding a NEW key
    // (or if we just deleted an existing key but the cache was still full)
    // we need to evict the Least Recently Used (LRU) item.
    // The problem states to use this specific eviction method.
    if (this.cache.size >= this.capacity) {
      // Get the oldest key (the first key in the Map's iteration order)
      const oldestKey = this.cache.keys().next().value;
      this.cache.delete(oldestKey); // Delete the oldest entry
    }

    // Add the new key-value pair (or re-add the updated one)
    this.cache.set(key, value);
  }
